package com.example.combined_schedule.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.combined_schedule.data.Work
import com.example.combined_schedule.data.WorkDao
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch

class CourseDetailViewModel(
    private val dao: WorkDao,
    val courseTitle: String
) : ViewModel() {

    val works: StateFlow<List<Work>> = dao.getWorksForCourse(courseTitle)
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5_000), emptyList())

    fun addWork(title: String, description: String, dueDate: String) {
        if (title.isBlank()) return
        viewModelScope.launch {
            dao.insert(Work(courseTitle = courseTitle, title = title, description = description, dueDate = dueDate))
        }
    }

    fun toggleComplete(work: Work) {
        viewModelScope.launch { dao.update(work.copy(isCompleted = !work.isCompleted)) }
    }

    fun deleteWork(work: Work) {
        viewModelScope.launch { dao.delete(work) }
    }

    class Factory(private val dao: WorkDao, private val courseTitle: String) : ViewModelProvider.Factory {
        @Suppress("UNCHECKED_CAST")
        override fun <T : ViewModel> create(modelClass: Class<T>): T =
            CourseDetailViewModel(dao, courseTitle) as T
    }
}

