// ── Color palette per type ────────────────────────────────────────────────────
private val courseColor       = Color(0xFF1565C0)   // blue
private val assignmentColor   = Color(0xFFB71C1C)   // red
private val specialEventColor = Color(0xFF2E7D32)   // green

private val courseContainerColor       = Color(0xFFE3F2FD)
private val assignmentContainerColor   = Color(0xFFFFEBEE)
private val specialEventContainerColor = Color(0xFFE8F5E9)

fun entryColor(type: EntryType) = when (type) {
    EntryType.COURSE        -> courseColor
    EntryType.ASSIGNMENT    -> assignmentColor
    EntryType.SPECIAL_EVENT -> specialEventColor
}

fun entryContainerColor(type: EntryType) = when (type) {
    EntryType.COURSE        -> courseContainerColor
    EntryType.ASSIGNMENT    -> assignmentContainerColor
    EntryType.SPECIAL_EVENT -> specialEventContainerColor
}

fun entryLabel(type: EntryType) = when (type) {
    EntryType.COURSE        -> "Course"
    EntryType.ASSIGNMENT    -> "DDL"
    EntryType.SPECIAL_EVENT -> "Event"
}

fun entryIcon(type: EntryType) = when (type) {
    EntryType.COURSE        -> Icons.Default.MenuBook
    EntryType.ASSIGNMENT    -> Icons.Default.Assignment
    EntryType.SPECIAL_EVENT -> Icons.Default.Star
}

// ── Screen ────────────────────────────────────────────────────────────────────
@Composable
fun ClassScheduleScreen() {
    val context = LocalContext.current
    val vm: ClassScheduleViewModel = viewModel(factory = ClassScheduleViewModel.Factory(context))
    val allEntries by vm.entries.collectAsState()

    var filterType by remember { mutableStateOf<EntryType?>(null) }
    var showDialog by remember { mutableStateOf(false) }
    var editingEntry by remember { mutableStateOf<ScheduleEntry?>(null) }

    val displayed = remember(allEntries, filterType) {
        val filtered = if (filterType == null) allEntries else allEntries.filter { it.type == filterType }
        filtered.sortedWith(compareBy({ it.date }, { it.time }))
    }

    Scaffold(
        floatingActionButton = {
            FloatingActionButton(
                onClick = { editingEntry = null; showDialog = true },
                containerColor = MaterialTheme.colorScheme.primary
            ) {
                Icon(Icons.Default.Add, contentDescription = "Add entry")
            }
        }
    ) { innerPadding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
        ) {
            // ── Title ────────────────────────────────────────────────────────
            Column(modifier = Modifier.padding(horizontal = 16.dp, vertical = 12.dp)) {
                Text(
                    text = "Combined Schedule",
                    style = MaterialTheme.typography.headlineSmall,
                    fontWeight = FontWeight.Bold
                )
                Text(
                    text = "Courses · Deadlines · Events",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }

            // ── Filter chips ─────────────────────────────────────────────────
            LazyRow(
                contentPadding = PaddingValues(horizontal = 16.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                item {
                    FilterChip(
                        selected = filterType == null,
                        onClick = { filterType = null },
                        label = { Text("All") }
                    )
                }
                items(EntryType.entries) { type ->
                    FilterChip(
                        selected = filterType == type,
                        onClick = { filterType = if (filterType == type) null else type },
                        label = { Text(entryLabel(type)) },
                        leadingIcon = {
                            Icon(
                                imageVector = entryIcon(type),
                                contentDescription = null,
                                modifier = Modifier.size(16.dp),
                                tint = entryColor(type)
                            )
                        }
                    )
                }
            }

            Spacer(Modifier.height(8.dp))

            // ── Entry list ───────────────────────────────────────────────────
            if (displayed.isEmpty()) {
                Box(
                    modifier = Modifier.fillMaxSize(),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(
                            Icons.Default.CalendarToday,
                            contentDescription = null,
                            modifier = Modifier.size(48.dp),
                            tint = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.4f)
                        )
                        Spacer(Modifier.height(12.dp))
                        Text(
                            "No entries yet. Tap + to add one.",
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            } else {
                LazyColumn(
                    contentPadding = PaddingValues(horizontal = 16.dp, vertical = 4.dp),
                    verticalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    items(displayed, key = { it.id }) { entry ->
                        ScheduleEntryCard(
                            entry = entry,
                            onEdit = { editingEntry = entry; showDialog = true },
                            onDelete = { vm.delete(entry) }
                        )
                    }
                    item { Spacer(Modifier.height(72.dp)) }
                }
            }
        }
    }

    if (showDialog) {
        EntryDialog(
            initial = editingEntry,
            onDismiss = { showDialog = false },
            onConfirm = { entry ->
                if (editingEntry == null) vm.insert(entry) else vm.update(entry)
                showDialog = false
            }
        )
    }
}

// ── Entry card ────────────────────────────────────────────────────────────────
@Composable
private fun ScheduleEntryCard(
    entry: ScheduleEntry,
    onEdit: () -> Unit,
    onDelete: () -> Unit
) {
    val accent = entryColor(entry.type)
    val container = entryContainerColor(entry.type)

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .clickable(onClick = onEdit),
        shape = RoundedCornerShape(12.dp),
        colors = CardDefaults.cardColors(containerColor = container),
        elevation = CardDefaults.cardElevation(defaultElevation = 2.dp)
    ) {
        Row(modifier = Modifier.height(IntrinsicSize.Min)) {
            // Colored left accent bar
            Box(
                modifier = Modifier
                    .width(5.dp)
                    .fillMaxHeight()
                    .background(accent, shape = RoundedCornerShape(topStart = 12.dp, bottomStart = 12.dp))
            )

            Column(
                modifier = Modifier
                    .weight(1f)
                    .padding(horizontal = 12.dp, vertical = 10.dp)
            ) {
                // Type chip + title row
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Surface(
                        shape = RoundedCornerShape(6.dp),
                        color = accent
                    ) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            modifier = Modifier.padding(horizontal = 6.dp, vertical = 2.dp),
                            horizontalArrangement = Arrangement.spacedBy(3.dp)
                        ) {
                            Icon(entryIcon(entry.type), contentDescription = null,
                                modifier = Modifier.size(11.dp), tint = Color.White)
                            Text(entryLabel(entry.type),
                                style = MaterialTheme.typography.labelSmall,
                                color = Color.White, fontWeight = FontWeight.SemiBold)
                        }
                    }
                    Text(
                        text = entry.title,
                        style = MaterialTheme.typography.bodyLarge,
                        fontWeight = FontWeight.SemiBold,
                        color = accent
                    )
                }

                if (entry.description.isNotBlank()) {
                    Spacer(Modifier.height(3.dp))
                    Text(
                        text = entry.description,
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }

                Spacer(Modifier.height(6.dp))

                // Date / time / location row
                Row(horizontalArrangement = Arrangement.spacedBy(12.dp)) {
                    if (entry.date.isNotBlank()) {
                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(3.dp)) {
                            Icon(Icons.Default.DateRange, null, modifier = Modifier.size(13.dp), tint = accent)
                            Text(entry.date, style = MaterialTheme.typography.labelSmall, color = accent)
                        }
                    }
                    if (entry.time.isNotBlank()) {
                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(3.dp)) {
                            Icon(Icons.Default.Schedule, null, modifier = Modifier.size(13.dp), tint = accent)
                            Text(entry.time, style = MaterialTheme.typography.labelSmall, color = accent)
                        }
                    }
                    if (entry.location.isNotBlank()) {
                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(3.dp)) {
                            Icon(Icons.Default.LocationOn, null, modifier = Modifier.size(13.dp), tint = accent)
                            Text(entry.location, style = MaterialTheme.typography.labelSmall, color = accent)
                        }
                    }
                }
            }

            // Delete button
            IconButton(
                onClick = onDelete,
                modifier = Modifier.align(Alignment.CenterVertically)
            ) {
                Icon(Icons.Default.Delete, contentDescription = "Delete",
                    modifier = Modifier.size(18.dp),
                    tint = accent.copy(alpha = 0.4f))
            }
        }
    }
}

// ── Add / Edit dialog ─────────────────────────────────────────────────────────
@Composable
private fun EntryDialog(
    initial: ScheduleEntry?,
    onDismiss: () -> Unit,
    onConfirm: (ScheduleEntry) -> Unit
) {
    var type        by remember { mutableStateOf(initial?.type        ?: EntryType.COURSE) }
    var title       by remember { mutableStateOf(initial?.title       ?: "") }
    var description by remember { mutableStateOf(initial?.description ?: "") }
    var date        by remember { mutableStateOf(initial?.date        ?: "") }
    var time        by remember { mutableStateOf(initial?.time        ?: "") }
    var location    by remember { mutableStateOf(initial?.location    ?: "") }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(if (initial == null) "Add Entry" else "Edit Entry") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {

                // Type selector
                Text("Type", style = MaterialTheme.typography.labelMedium,
                    color = MaterialTheme.colorScheme.onSurfaceVariant)
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    EntryType.entries.forEach { t ->
                        FilterChip(
                            selected = type == t,
                            onClick = { type = t },
                            label = { Text(entryLabel(t), style = MaterialTheme.typography.labelSmall) },
                            colors = FilterChipDefaults.filterChipColors(
                                selectedContainerColor = entryColor(t),
                                selectedLabelColor = Color.White
                            )
                        )
                    }
                }

                OutlinedTextField(value = title, onValueChange = { title = it },
                    label = { Text("Title *") }, singleLine = true,
                    modifier = Modifier.fillMaxWidth())
                OutlinedTextField(value = description, onValueChange = { description = it },
                    label = { Text("Description") }, maxLines = 2,
                    modifier = Modifier.fillMaxWidth())
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    OutlinedTextField(value = date, onValueChange = { date = it },
                        label = { Text("Date") }, singleLine = true,
                        modifier = Modifier.weight(1f))
                    OutlinedTextField(value = time, onValueChange = { time = it },
                        label = { Text("Time") }, singleLine = true,
                        modifier = Modifier.weight(1f))
                }
                OutlinedTextField(value = location, onValueChange = { location = it },
                    label = { Text("Location") }, singleLine = true,
                    modifier = Modifier.fillMaxWidth())
            }
        },
        confirmButton = {
            TextButton(
                onClick = {
                    onConfirm(
                        ScheduleEntry(
                            id          = initial?.id ?: java.util.UUID.randomUUID().toString(),
                            type        = type,
                            title       = title.trim(),
                            description = description.trim(),
                            date        = date.trim(),
                            time        = time.trim(),
                            location    = location.trim()
                        )
                    )
                },
                enabled = title.isNotBlank()
            ) { Text(if (initial == null) "Add" else "Save") }
        },
        dismissButton = { TextButton(onClick = onDismiss) { Text("Cancel") } }
    )
}

